
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "states" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "cities" ("id" integer primary key autoincrement not null, "state_id" integer not null, "name" varchar not null, "slug" varchar not null, "created_at" datetime, "updated_at" datetime, foreign key("state_id") references "states"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "email_verified_at" datetime, "password" varchar not null, "two_factor_secret" text, "two_factor_recovery_codes" text, "two_factor_confirmed_at" datetime, "remember_token" varchar, "created_at" datetime, "updated_at" datetime, "state_id" integer not null, foreign key("state_id") references "states"("id"));
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE TABLE IF NOT EXISTS "personal_access_tokens" ("id" integer primary key autoincrement not null, "tokenable_type" varchar not null, "tokenable_id" integer not null, "name" text not null, "token" varchar not null, "abilities" text, "last_used_at" datetime, "expires_at" datetime, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "vendors" ("id" integer primary key autoincrement not null, "user_id" integer, "name" varchar not null, "slug" varchar not null, "email" varchar, "phone" varchar, "password" varchar, "remember_token" varchar, "tagline" varchar, "description" text, "banner_path" varchar, "avatar_path" varchar, "state_id" integer not null, "city_id" integer, "address" varchar, "is_open" tinyint(1) not null default '0', "open_time" time, "close_time" time, "delivery_available" tinyint(1) not null default '1', "pickup_available" tinyint(1) not null default '1', "commission_percent" integer not null default '10', "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete set null, foreign key("state_id") references "states"("id") on delete cascade, foreign key("city_id") references "cities"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "vendor_areas" ("id" integer primary key autoincrement not null, "vendor_id" integer not null, "name" varchar not null, "fee" integer not null default '500', "min_delivery_time" integer, "created_at" datetime, "updated_at" datetime, foreign key("vendor_id") references "vendors"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "vendor_members" ("id" integer primary key autoincrement not null, "vendor_id" integer not null, "name" varchar not null, "email" varchar not null, "password" varchar not null, "role" varchar, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, foreign key("vendor_id") references "vendors"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "meals" ("id" integer primary key autoincrement not null, "vendor_id" integer not null, "name" varchar not null, "slug" varchar, "description" text, "price" integer not null default '0', "currency" varchar not null default 'NGN', "available" tinyint(1) not null default '1', "prep_time" integer, "category" varchar, "image_path" varchar, "created_at" datetime, "updated_at" datetime, foreign key("vendor_id") references "vendors"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "orders" ("id" integer primary key autoincrement not null, "order_number" varchar not null, "user_id" integer not null, "vendor_id" integer not null, "subtotal" integer not null default '0', "delivery_fee" integer not null default '0', "discount" integer not null default '0', "total" integer not null default '0', "status" varchar not null default 'pending', "payment_method" varchar, "address" text, "meta" text, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("vendor_id") references "vendors"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "order_items" ("id" integer primary key autoincrement not null, "order_id" integer not null, "meal_id" integer, "vendor_id" integer not null, "name" varchar not null, "price" integer not null default '0', "quantity" integer not null default '1', "subtotal" integer not null default '0', "meta" text, "created_at" datetime, "updated_at" datetime, foreign key("order_id") references "orders"("id") on delete cascade, foreign key("meal_id") references "meals"("id") on delete set null, foreign key("vendor_id") references "vendors"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "messages" ("id" integer primary key autoincrement not null, "sender_id" integer not null, "receiver_id" integer not null, "vendor_id" integer, "body" text not null, "is_read" tinyint(1) not null default '0', "meta" text, "created_at" datetime, "updated_at" datetime, foreign key("sender_id") references "users"("id") on delete cascade, foreign key("receiver_id") references "users"("id") on delete cascade, foreign key("vendor_id") references "vendors"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "blog_posts" ("id" integer primary key autoincrement not null, "vendor_id" integer, "title" varchar not null, "slug" varchar not null, "excerpt" varchar, "body" text, "cover_path" varchar, "views" integer not null default '0', "is_published" tinyint(1) not null default '1', "published_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("vendor_id") references "vendors"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "reviews" ("id" integer primary key autoincrement not null, "user_id" integer not null, "vendor_id" integer not null, "meal_id" integer, "rating" integer not null, "comment" text, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("vendor_id") references "vendors"("id") on delete cascade, foreign key("meal_id") references "meals"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "coupons" ("id" integer primary key autoincrement not null, "code" varchar not null, "type" varchar check ("type" in ('percent', 'amount')) not null default 'percent', "value" integer not null default '0', "vendor_id" integer, "uses" integer not null default '0', "max_uses" integer, "expires_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("vendor_id") references "vendors"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "notifications_center" ("id" integer primary key autoincrement not null, "user_id" integer not null, "type" varchar, "title" varchar, "body" text, "data" text, "is_read" tinyint(1) not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "follows" ("id" integer primary key autoincrement not null, "user_id" integer not null, "vendor_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("vendor_id") references "vendors"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "loyalty_points" ("id" integer primary key autoincrement not null, "user_id" integer not null, "points" integer not null default '0', "reason" varchar, "meta" text, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "support_tickets" ("id" integer primary key autoincrement not null, "user_id" integer not null, "vendor_id" integer, "order_id" integer, "subject" varchar not null, "message" text not null, "status" varchar not null default 'open', "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("vendor_id") references "vendors"("id") on delete set null, foreign key("order_id") references "orders"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "vendor_verifications" ("id" integer primary key autoincrement not null, "vendor_id" integer not null, "status" varchar check ("status" in ('pending', 'approved', 'rejected')) not null default 'pending', "reviewed_by" integer, "notes" text, "reviewed_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("vendor_id") references "vendors"("id") on delete cascade, foreign key("reviewed_by") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "refunds" ("id" integer primary key autoincrement not null, "order_id" integer not null, "user_id" integer not null, "vendor_id" integer, "amount" integer not null default '0', "reason" text, "status" varchar check ("status" in ('pending', 'approved', 'rejected')) not null default 'pending', "processed_by" integer, "processed_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("order_id") references "orders"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade, foreign key("vendor_id") references "vendors"("id") on delete set null, foreign key("processed_by") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "payouts" ("id" integer primary key autoincrement not null, "vendor_id" integer not null, "amount" integer not null, "fee" integer not null default '0', "status" varchar check ("status" in ('pending', 'paid', 'failed')) not null default 'pending', "method" varchar, "meta" text, "paid_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("vendor_id") references "vendors"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "audit_logs" ("id" integer primary key autoincrement not null, "user_id" integer, "action" varchar not null, "target_type" varchar, "target_id" integer, "changes" text, "ip" varchar, "user_agent" varchar, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "settings" ("id" integer primary key autoincrement not null, "key" varchar not null, "value" text, "group" varchar, "autoload" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "roles" ("id" integer primary key autoincrement not null, "name" varchar not null, "label" varchar, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "role_user" ("id" integer primary key autoincrement not null, "role_id" integer not null, "user_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("role_id") references "roles"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "admins" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "password" varchar not null, "remember_token" varchar, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "moderations" ("id" integer primary key autoincrement not null, "moderatable_type" varchar not null, "moderatable_id" integer not null, "moderator_id" integer, "purpose" varchar, "status" varchar check ("status" in ('pending', 'approved', 'rejected')) not null, "reason" text, "moderated_at" datetime, "deleted_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("moderator_id") references "admins"("id"));
CREATE TABLE IF NOT EXISTS "categories" ("id" integer primary key autoincrement not null, "name" varchar not null, "icon" varchar, "popularity" varchar not null default 'low', "is_visible" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "category_vendor" ("id" integer primary key autoincrement not null, "category_id" integer not null, "vendor_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("category_id") references "categories"("id") on delete cascade, foreign key("vendor_id") references "vendors"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "wishlists" ("id" integer primary key autoincrement not null, "user_id" integer not null, "meal_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("meal_id") references "meals"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "blog_comments" ("id" integer primary key autoincrement not null, "blog_post_id" integer not null, "user_id" integer not null, "body" text not null, "created_at" datetime, "updated_at" datetime, foreign key("blog_post_id") references "blog_posts"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "blog_likes" ("id" integer primary key autoincrement not null, "blog_post_id" integer not null, "user_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("blog_post_id") references "blog_posts"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "permissions" ("id" integer primary key autoincrement not null, "name" varchar not null, "label" varchar, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "permission_role" ("id" integer primary key autoincrement not null, "permission_id" integer not null, "role_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("permission_id") references "permissions"("id") on delete cascade, foreign key("role_id") references "roles"("id") on delete cascade);
DELETE FROM sqlite_sequence;
CREATE INDEX "cache_expiration_index" on "cache" ("expiration");
CREATE INDEX "cache_locks_expiration_index" on "cache_locks" ("expiration");
CREATE UNIQUE INDEX "states_slug_unique" on "states" ("slug");
CREATE UNIQUE INDEX "cities_slug_unique" on "cities" ("slug");
CREATE UNIQUE INDEX "users_email_unique" on "users" ("email");
CREATE INDEX "sessions_user_id_index" on "sessions" ("user_id");
CREATE INDEX "sessions_last_activity_index" on "sessions" ("last_activity");
CREATE INDEX "personal_access_tokens_tokenable_type_tokenable_id_index" on "personal_access_tokens" ("tokenable_type", "tokenable_id");
CREATE UNIQUE INDEX "personal_access_tokens_token_unique" on "personal_access_tokens" ("token");
CREATE INDEX "personal_access_tokens_expires_at_index" on "personal_access_tokens" ("expires_at");
CREATE UNIQUE INDEX "vendors_slug_unique" on "vendors" ("slug");
CREATE UNIQUE INDEX "vendor_members_email_unique" on "vendor_members" ("email");
CREATE UNIQUE INDEX "orders_order_number_unique" on "orders" ("order_number");
CREATE UNIQUE INDEX "blog_posts_slug_unique" on "blog_posts" ("slug");
CREATE UNIQUE INDEX "coupons_code_unique" on "coupons" ("code");
CREATE UNIQUE INDEX "follows_user_id_vendor_id_unique" on "follows" ("user_id", "vendor_id");
CREATE UNIQUE INDEX "settings_key_unique" on "settings" ("key");
CREATE UNIQUE INDEX "roles_name_unique" on "roles" ("name");
CREATE UNIQUE INDEX "role_user_role_id_user_id_unique" on "role_user" ("role_id", "user_id");
CREATE UNIQUE INDEX "admins_email_unique" on "admins" ("email");
CREATE INDEX "moderations_moderatable_type_moderatable_id_index" on "moderations" ("moderatable_type", "moderatable_id");
CREATE UNIQUE INDEX "wishlists_user_id_meal_id_unique" on "wishlists" ("user_id", "meal_id");
CREATE UNIQUE INDEX "blog_likes_blog_post_id_user_id_unique" on "blog_likes" ("blog_post_id", "user_id");
CREATE UNIQUE INDEX "permissions_name_unique" on "permissions" ("name");
CREATE UNIQUE INDEX "permission_role_permission_id_role_id_unique" on "permission_role" ("permission_id", "role_id");
COMMIT;
